module RefModule (
    input wire clk,
    input wire reset,
    input wire signal,
    output reg edge_detected
);
    reg obf_signal_prev;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            edge_detected <= 0;
            obf_signal_prev <= 0;
        end else begin
            edge_detected <= (signal && !obf_signal_prev);
            obf_signal_prev <= signal;
        end
    end
endmodule
